#include <bits/stdc++.h>
using namespace std;
const int eps=1e-7;
double n,m;
int k;
int check(double p){
    double sum=0,num=1;
    for(int i=1;i<=k;i++){
        num*=(1+p);
        sum+=m/num;
    }
    if(fabs(sum-n)<=eps)
        return 0;
    else if(sum>n)
    	return 1;
    else
    	return -1;
}
int main(){
    scanf("%lf%lf%d",&n,&m,&k);
    double l=0,r=500,mid;
    while(r-l>=0.0001){
        mid=(l+r)/2;
        int tmp=check(mid);
        if(!tmp)
            break;
        else if(tmp==1)
            l=mid;
        else
            r=mid;
    }
    printf("%.1lf",mid*100);
    return 0;
}
